form:Form.form:Scripts:
		var report_window = null;
function set_report_window (obj)
{
	report_window = obj;
}

function OnLoad()
{
	var XMLEva=GetProxy().SQLService().GetXML(Ctrl("main").getResource("DATA_ADIC"), '<DATA oi_evaluacion="'+Ctrl("oi_evaluacion").GetXValue()+'" />');
	var rep = XMLEva.GetAttr('d_reporte').substr(0, XMLEva.GetAttr('d_reporte').lastIndexOf('.'));
 	var editable = Ctrl("EDITABLE").GetXValue();
    var oi_evaluador360;
	var modo = Ctrl("modo").GetXValue();

	// Setea el titulo de la ventana
	var titulo = Ctrl('GEN');
	if (modo == 'PREEVALUAR')
		titulo.SetText('Ingreso de Datos');
	if (modo == 'EVALUADO')
		titulo.SetText('Autoevaluación de Desempeño');
	if (modo == 'EVALUADOR')
		titulo.SetText('Evaluación de Desempeño');
	if (modo == 'SUPERVISOR')
		titulo.SetText('Validación de Evaluación');
	if (modo == 'EVALUADOR360')
	{
		titulo.SetText('Evaluación de Desempeño');
		var XMLEva360=GetProxy().SQLService().GetXML(Ctrl("main").getResource("EVALUADORES360"), '<DATA oi_evaluacion="'+Ctrl("oi_evaluacion").GetXValue()+'" />');
	    oi_evaluador360 = XMLEva360.GetAttr('oi_evaluador360');
	}

	if (modo == 'APROBAR')
		titulo.SetText('Aprobación / Rechazo de Evaluación');
	if (modo == 'POSAPROBAR')
		titulo.SetText('Cierre de Evaluación');
	if (modo == 'SHOW')
		titulo.SetText('Consulta de Evaluación');

	 // Setea el titulo de la pestaña
	 g_FFConnect.ObjectManager.SetWindowTitle(titulo.GetText(), g_FFConnect);

	if(Ctrl('main').GetMode()=='PORTAL')
		url="../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file="+rep+"&mode="+modo+"&oi_evaluacion="+Ctrl("oi_evaluacion").GetXValue()+"&portal=1&editable="+editable+"&oi_evaluador_360="+oi_evaluador360;
	else
		url="../../../ReportViewer.aspx?ut="+GetProxy().UserToken()+"&file="+rep+"&mode="+modo+"&oi_evaluacion="+Ctrl("oi_evaluacion").GetXValue()+"&portal=0&editable="+editable+"&oi_evaluador_360="+oi_evaluador360;
	Ctrl("URLREPORT").SetURL(url);
}


function PRINT()
{
	var _iframe = window.frames['URLREPORT_FRAME'];
	_iframe.focus();
	_iframe.print();
}                         

function GET_DDO()
{             
	var OBJ=new NomadXML(GetProxy().DDOService().Get("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION",Ctrl("oi_evaluacion").GetXValue()));
 	OBJ.SetAttr("nmd-status","~u,");

	var EVA=OBJ.FirstChild();
	if (report_window==null)
		report_window = window.frames['URLREPORT_FRAME'];
	report_window.DDOCHANGE(EVA);

	return OBJ;
}             

function isFinish(EVA)
{                                                  
	var retval=true;
	var XMLEva=GetProxy().SQLService().GetXML(Ctrl("main").getResource("DATA_ADIC"), '&lt;DATA oi_evaluacion="'+Ctrl("oi_evaluacion").GetXValue()+'" /&gt;');

	if (EVA.GetAttr("n_resultado")=="") retval=false;
	if (XMLEva.GetAttr("l_eva2")=="1") if (EVA.GetAttr("n_resultado2")=="") retval=false;
	if (XMLEva.GetAttr("l_eva3")=="1") if (EVA.GetAttr("n_resultado3")=="") retval=false;

	return retval;
}

function CHECK_COMPLETE()
{
	if (report_window==null)
		report_window = window.frames['URLREPORT_FRAME'];

	if (!report_window.IsComplete())
		return confirm("Existen Items sin Completar\nDesea Continuar?")
	return true;
}


function EVALUADO()
{                    
	var OBJ=GET_DDO();
	var EVA=OBJ.FirstChild();     
	var proxy=new NomadProxy();
	var RPC=proxy.RPCService();

	if (!CHECK_COMPLETE()) return;

	//Guardar DDO	
	EVA.SetAttr("f_evaluacion", date2str(new Date()));
 	RPC.AddParam(new NomadRPCParam("e"    , "IN" , OBJ, "NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION"));
	RPC.AddParam(new NomadRPCParam("Estado", "IN" , isFinish(EVA)?"EV":"HA"));

	RPC.Execute("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION","CambiarEstado");
	Ctrl("main").DoEvent("BACK");
}

// Solo guardar
function SAVE()
{
	var OBJ=GET_DDO();
	var EVA=OBJ.FirstChild();

	if (!CHECK_COMPLETE()) return;

    //Guardar DDO	
	EVA.SetAttr("f_evaluacion", date2str(new Date()));
	GetProxy().DDOService().Set("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION", OBJ.ToString());
 	Ctrl("main").DoEvent("BACK");
}

// Guardar y cambiar estado
function SAVE_CE()
{
	var OBJ=GET_DDO();
	var EVA=OBJ.FirstChild();
    var proxy=new NomadProxy();
    var CAMBIO_ESTADO = Ctrl('CAMBIO_ESTADO').GetXValue();

	if (CAMBIO_ESTADO != '')
	{
		if (!(CAMBIO_ESTADO=='AB' || CAMBIO_ESTADO=='HA'))
			if (!isFinish(EVA))
			{
				alert("La evaluaci&#243;n no está completa.");
				return;
			}

		// Cambio estado
	    var RPC=proxy.RPCService(); 
		EVA.SetAttr("f_evaluacion", date2str(new Date()));
	 	RPC.AddParam(new NomadRPCParam("e"    , "IN" , OBJ, "NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION"));
		RPC.AddParam(new NomadRPCParam("Estado", "IN" , CAMBIO_ESTADO));
		RPC.Execute("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION","CambiarEstado");
	}
	else
	{
		if (!CHECK_COMPLETE()) return;
		//Guardar DDO	
		EVA.SetAttr("f_evaluacion", date2str(new Date()));
	 	GetProxy().DDOService().Set("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION", OBJ.ToString());
	}

	Ctrl("main").DoEvent("BACK");
}           

function CONFIRM()
{
	var OBJ=GET_DDO();
	var EVA=OBJ.FirstChild();
	var proxy=new NomadProxy();
	var RPC=proxy.RPCService();

	//Puede ser confirmada?	
	if (!isFinish(EVA)) 
	{
		alert("La evaluaci&#243;n tiene que estar Evaluada para poder Confirmarse.");
		return;
	}

	//Guardar DDO	
	EVA.SetAttr("f_evaluacion", date2str(new Date()));
 	RPC.AddParam(new NomadRPCParam("e"    , "IN" , OBJ, "NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION"));
	RPC.AddParam(new NomadRPCParam("Estado", "IN" , "CO"));

	RPC.Execute("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION","CambiarEstado");
	Ctrl("main").DoEvent("BACK");
}

function APROBAR()
{
	var OBJ=GET_DDO();
	var EVA=OBJ.FirstChild();  
	var proxy=new NomadProxy();
	var RPC=proxy.RPCService();

	if (!isFinish(EVA))
	{
		alert("La evaluaci&#243;n tiene que estar Evaluada o Confirmada para poder Aprobarse.");
		return;
	}

	//Guardar DDO	
	RPC.AddParam(new NomadRPCParam("e"    , "IN" , OBJ, "NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION"));
	RPC.AddParam(new NomadRPCParam("Estado", "IN" , "AP"));

	RPC.Execute("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION","CambiarEstado");
	Ctrl("main").DoEvent("BACK");
}

function RECHAZAR()
{
	var OBJ=GET_DDO();
	var EVA=OBJ.FirstChild();
	var proxy=new NomadProxy();
	var RPC=proxy.RPCService();

	if (!isFinish(EVA))
	{
		alert("La evaluaci&#243;n tiene que estar Evaluada o Confirmada para poder Rechazarce.");
		return;
	}

	//Guardar DDO	
	RPC.AddParam(new NomadRPCParam("e"    , "IN" , OBJ, "NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION"));
	RPC.AddParam(new NomadRPCParam("Estado", "IN" , "RZ"));

	RPC.Execute("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION","CambiarEstado");

	Ctrl("main").DoEvent("BACK");
}

function CERRAR()
{
	var OBJ=GET_DDO();
	var EVA=OBJ.FirstChild();
	var proxy=new NomadProxy();
	var RPC=proxy.RPCService();

	if (!isFinish(EVA))
	{
		alert("La evaluaci&#243;n tiene que estar Evaluada, Confirmada o Aprobada para poder Cerrarse.");
		return;
	}

	//Guardar DDO	
	RPC.AddParam(new NomadRPCParam("e"    , "IN" , OBJ, "NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION"));
	RPC.AddParam(new NomadRPCParam("Estado", "IN" , "CE"));

	RPC.Execute("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION","CambiarEstado");
	Ctrl("main").DoEvent("BACK");
}
